use macroquad::prelude::*;

mod player;
mod physics;
mod world;

use player::Player;
use world::World;

#[macroquad::main("{{project_name}}")]
async fn main() {
    println!("Starting {{project_name}}...");

    let mut world = World::new();
    let mut player = Player::new(100.0, 100.0);

    loop {
        clear_background(SKYBLUE);

        // Update
        let dt = get_frame_time();
        player.update(dt, &world);

        // Draw
        world.draw();
        player.draw();

        // Instructions
        draw_text("Arrow keys to move, Space to jump", 10.0, 20.0, 20.0, BLACK);

        next_frame().await
    }
}

