use macroquad::prelude::*;
use crate::physics::PhysicsBody;
use crate::world::World;

pub struct Player {
    pub physics: PhysicsBody,
    pub speed: f32,
    pub jump_force: f32,
    pub on_ground: bool,
}

impl Player {
    pub fn new(x: f32, y: f32) -> Self {
        Self {
            physics: PhysicsBody::new(x, y, 32.0, 32.0),
            speed: 200.0,
            jump_force: 400.0,
            on_ground: false,
        }
    }

    pub fn update(&mut self, dt: f32, world: &World) {
        // Input
        if is_key_down(KeyCode::Left) {
            self.physics.velocity.x = -self.speed;
        } else if is_key_down(KeyCode::Right) {
            self.physics.velocity.x = self.speed;
        } else {
            self.physics.velocity.x = 0.0;
        }

        // Jump
        if is_key_pressed(KeyCode::Space) && self.on_ground {
            self.physics.velocity.y = -self.jump_force;
            self.on_ground = false;
        }

        // Apply gravity
        self.physics.apply_gravity(dt);

        // Update position
        self.physics.update(dt);

        // Collision with world
        self.on_ground = false;
        for platform in world.get_platforms() {
            if self.physics.rect.intersect(platform) {
                // Simple collision resolution
                if self.physics.velocity.y > 0.0 {
                    self.physics.rect.y = platform.y - self.physics.rect.h;
                    self.physics.velocity.y = 0.0;
                    self.on_ground = true;
                }
            }
        }

        // Screen boundaries
        self.physics.rect.x = self.physics.rect.x.clamp(0.0, screen_width() - self.physics.rect.w);
    }

    pub fn draw(&self) {
        draw_rectangle(
            self.physics.rect.x,
            self.physics.rect.y,
            self.physics.rect.w,
            self.physics.rect.h,
            RED,
        );
    }
}

