use macroquad::prelude::*;

pub struct World {
    platforms: Vec<Rect>,
}

impl World {
    pub fn new() -> Self {
        let mut platforms = Vec::new();

        // Ground
        platforms.push(Rect::new(0.0, 500.0, 800.0, 100.0));

        // Some platforms
        platforms.push(Rect::new(200.0, 400.0, 150.0, 20.0));
        platforms.push(Rect::new(450.0, 300.0, 150.0, 20.0));
        platforms.push(Rect::new(100.0, 200.0, 100.0, 20.0));

        Self { platforms }
    }

    pub fn get_platforms(&self) -> &Vec<Rect> {
        &self.platforms
    }

    pub fn draw(&self) {
        for platform in &self.platforms {
            draw_rectangle(platform.x, platform.y, platform.w, platform.h, GREEN);
        }
    }
}
